//// KAPITEL 2 //// UTILITIES //////////////////////////////////////////////////////////////////////
//// KAPITEL 2.1 // Mini-UI ////////////////////////////////////////////////////////////////////////
function smxToast(msg, ok = true) {
  try { if (typeof toast === 'function') { toast(msg, ok); return; } } catch {}
  try {
    const el = document.createElement('div');
    el.textContent = String(msg ?? '');
    el.style.cssText = 'position:fixed;right:12px;top:12px;z-index:2147483647;'
      + 'background:' + (ok ? '#0b1e2d' : '#5c0d0d') + ';color:#fff;'
      + 'padding:8px 10px;border-radius:8px;border:1px solid rgba(255,255,255,.15);'
      + 'font:13px/1.35 system-ui,Segoe UI,Arial,sans-serif;';
    document.body.appendChild(el);
    setTimeout(() => { try { el.remove(); } catch {} }, 2200);
  } catch { try { console.log('[SMX]', ok ? 'OK:' : 'ERR:', msg); } catch {} }
}
function smxCreateOverlayBox(html){
const wrap=document.createElement('div');
wrap.style.cssText='position:fixed; inset:0; z-index:2147483647; display:flex; align-items:center; justify-content:center; background:rgba(0,0,0,.35)';
const box=document.createElement('div');
box.style.cssText='background:#0b1e2d; color:#fff; border:1px solid #0d3a5c; border-radius:12px; max-width:820px; width:min(96vw,820px); box-shadow:0 12px 36px rgba(0,0,0,.4); font:13px/1.4 system-ui, Segoe UI, Arial; padding:14px;';
box.innerHTML=html;
wrap.appendChild(box);
document.body.appendChild(wrap);
return {wrap, box};
}

//// KAPITEL 2.2 // CFG-Reader /////////////////////////////////////////////////////////////////////
function smxGetCfgProfile(adapterId) {
try {
const cfg = (typeof window.SMX_CFG === 'object' && window.SMX_CFG && window.SMX_CFG.profiles)
? window.SMX_CFG.profiles : {};
return cfg?.[adapterId] || {};
} catch { return {}; }
}


//// KAPITEL 2.3 // GLOBALE HELPER für "Absatz einfügen" & Body-Editoren ///////////////////////////
/*
 * CUE: Body besteht aus mehreren "Paragraph"-Story-Elementen.
 * Vor dem Neuschreiben müssen diese leer + (bis auf eines) gelöscht werden.
 * Ergebnis: genau 1 sichtbarer Body-Paragraph bleibt, leer (Quill-Empty = "\n").
 * @param {object} opts
 * @param {Document|Element} opts.scope DOM-Scope (Tabpanel o.ä.)
 * @param {number} opts.keep Wie viele Paragraph-Elemente sollen bleiben? (Default 1)
 * @param {number} opts.maxRemove Sicherheitslimit gegen Endlosschleifen
 * @param {boolean} opts.toast Kurzes Feedback per smxToast
 * @returns {Promise<{ok:boolean, removed:number, remaining:number, cleared:number}>}
*/

// Findet den "Absatz einfügen"-Button (harter Selector nach deinem DOM-Snippet)
function cueFindAddParagraphButtonStrict(root = document) {
  return (
    deepQS('div.cue-icon.paragraph.predefined[title*="Absatz einfügen" i]', root) ||
    deepQS('div.cue-icon.paragraph.predefined[title*="absatz" i]', root)
  );
}

// Klickt "Absatz einfügen" (erst Adapter-Helper, dann harter Selector)
async function cueClickAddParagraph(root = document) {
  // 1) Adapter-Helper (falls vorhanden)
  try {
    const btn = (typeof CUE === 'object' && CUE?._tabs?.cueFindAddParagraphButton)
      ? CUE._tabs.cueFindAddParagraphButton(root)
      : null;
    if (btn) { btn.click(); await sleep(120); return true; }
  } catch {}

  // 2) Harte Variante
  const strict = cueFindAddParagraphButtonStrict(root);
  if (strict) { strict.click(); await sleep(120); return true; }

  return false;
}

// CUE: Speichern-Button Helper (SuperSHIRT Safety)
function cueFindSaveButtonStrict(root = document) {
  try {
  // 1) Harte Selektoren (dein Umgebungscode)
    const hard =
      deepQS('input#save[data-testid="online-media-editor-save-button"]', root) ||
      deepQS('input#save', root) ||
      deepQS('input[data-testid="online-media-editor-save-button"]', root) ||
      deepQS('button#save', root) ||
      deepQS('button[data-testid="online-media-editor-save-button"]', root);

    if (hard && isVisible(hard)) return hard;

  // 2) Fallback: sichtbarer Button/Input mit Text/Value "Speichern"
    const candidates = deepQSA('button, input[type="button"], input[type="submit"]', root).filter(isVisible);
    const btn = candidates.find(el => {
      const t = String(el.value || el.innerText || el.textContent || '').trim();
      return /speichern/i.test(t);
    });
    return btn || null;
  } catch {
    return null;
  }
}

async function cueClickSaveButtonSafe({ timeout = 6000, quiet = true } = {}) {
  const btn = cueFindSaveButtonStrict(document);
  if (!btn) {
    if (!quiet) smxToast('SuperSHIRT: Speichern-Button nicht gefunden (übersprungen).', false);
    return false;
  }

  const isDisabled = (el) =>
    !!(el.disabled ||
       el.getAttribute?.('aria-disabled') === 'true' ||
       el.hasAttribute?.('disabled'));

  try { btn.click(); } catch { try { btn.dispatchEvent(new MouseEvent('click', { bubbles: true })); } catch {} }

  // Viele UIs setzen kurz disabled/aria-disabled. Wir warten kurz auf "busy" und dann auf "ready".
  const start = Date.now();
  let sawBusy = false;

  // 1) kurze Phase: Busy erkennen (max 900ms)
  while (Date.now() - start < Math.min(900, timeout)) {
    if (isDisabled(btn)) { sawBusy = true; break; }
    await sleep(60);
  }

  // 2) wenn busy gesehen: auf Ende warten (bis timeout)
  if (sawBusy) {
    while (Date.now() - start < timeout) {
      if (!isDisabled(btn)) break;
      await sleep(90);
    }
  } else {
    // ansonsten nur Mini-Delay (klick registrieren lassen)
    await sleep(220);
  }

  return true;
}

// Liefert deduplizierte Liste der echten Body-Editoren (1 Editor pro Absatz)
function cueGetBodyParagraphEditors(scope = document) {
  const pickEditor = (root) =>
    deepQS('.ql-editor[contenteditable="true"]', root) ||
    deepQS('[contenteditable="true"]', root) ||
    deepQS('textarea, [role="textbox"]', root);

  let editors = [];

  // Primär: Story-Container (stabil pro Absatz)
  const story = deepQSA('[data-testid="story-element-se_paragraph"]', scope).filter(isVisible);
  if (story.length) {
    for (const c of story) {
      const ed = pickEditor(c);
      if (ed) editors.push(ed);
    }
  } else {
  // Fallback: Feld-Container
    const fields = deepQSA('[data-testid="se_paragraph_field"]', scope).filter(isVisible);
    for (const f of fields) {
      const ed = pickEditor(f);
      if (ed) editors.push(ed);
    }
  }

  // Dedupe nach Element-Referenz
  const uniq = [];
  const seen = new Set();
  for (const ed of editors) {
    if (!seen.has(ed)) { seen.add(ed); uniq.push(ed); }
  }
  return uniq;
}

// Stellt sicher, dass mindestens `need` Body-Absätze existieren. Erst CUE._tabs.cueEnsureBodyParagraphElements versuchen, dann Click-Fallback.
async function cueEnsureBodyParagraphEditorsStrict(need, scope = document, { timeout = 7000 } = {}) {
  need = Math.max(1, Number(need || 1));

  // 1) Erst Adapter-Funktion (wenn vorhanden)
  try {
    if (typeof CUE === 'object' && CUE?._tabs?.cueEnsureBodyParagraphElements) {
      await CUE._tabs.cueEnsureBodyParagraphElements(need, scope);
      await sleep(150);
    }
  } catch {}

  // 2) Prüfen
  let editors = cueGetBodyParagraphEditors(scope);
  if (editors.length >= need) return editors;

  // 3) Click-Fallback: "Absatz einfügen" bis genug da sind
  const start = Date.now();
  while (editors.length < need && (Date.now() - start) < timeout) {
    const ok = await cueClickAddParagraph(scope);
    if (!ok) break;

    // warten bis ein weiterer Editor auftaucht
    const prev = editors.length;
    await waitFor(() => cueGetBodyParagraphEditors(scope).length > prev, { timeout: 3000, poll: 80, root: document.body });

    editors = cueGetBodyParagraphEditors(scope);
  }

  return editors;
}

async function cueCleanBodyToSingleParagraph(opts = {}) {
  const scope = opts.scope ?? document;
  const keep = Math.max(1, Number(opts.keep ?? 1));
  const maxRemove = Math.max(1, Number(opts.maxRemove ?? 30));
  const doToast = opts.toast ?? false;

  // simple Lock (verhindert Doppelklick/Parallelruns)
  if (cueCleanBodyToSingleParagraph.__lock) {
    return { ok: true, removed: 0, remaining: 0, cleared: 0 };
  }
  cueCleanBodyToSingleParagraph.__lock = true;

  let removed = 0;
  let cleared = 0;

  try {
    // Body TESTIDs – zur Laufzeit vorhanden (CUE ist in Kapitel 3.4 definiert)
    const bodyIds =
      (typeof CUE === 'object' && CUE?._tabs?.TESTIDS?.body) ??
      ['se_paragraph_field', 'story-element-se_paragraph'];

    const hostSelector = bodyIds.map(id => `[data-testid="${id}"]`).join(',');

    const getHosts = () =>
      deepQSA(hostSelector, scope).filter(isVisible);

    const pickEditor = (host) =>
      deepQS('.ql-editor[contenteditable="true"]', host) ||
      deepQS('[contenteditable="true"]', host) ||
      deepQS('textarea, input[type="text"], input[type="search"], [role="textbox"]', host);

    const getQuill = (editorEl) => {
      try {
        const container =
          editorEl?.closest?.('.ql-container') ||
          editorEl?.closest?.('[class*="ql-container"]');
        return container?.__quill ?? null;
      } catch { return null; }
    };

    const clearEditor = (editorEl) => {
      if (!editorEl) return false;
      if (typeof SMX_DRY_RUN !== 'undefined' && SMX_DRY_RUN) return true;

      // Quill leer machen (Quill-Empty = "\n")
      try {
        const q = getQuill(editorEl);
        if (q) {
          q.focus?.();
          try { q.deleteText(0, Math.max(0, (q.getLength?.() ?? 0)), 'user'); } catch {}
          try { q.setText('', 'user'); } catch {}
          // Events
          try { (q.root ?? editorEl).dispatchEvent(new InputEvent('input', { bubbles: true })); } catch {}
          try { (q.root ?? editorEl).dispatchEvent(new Event('change', { bubbles: true })); } catch {}
          return true;
        }
      } catch {}

      // Fallback: generisch
      try {
        writeGeneric(editorEl, '');
        return true;
      } catch {}
      return false;
    };

    const findDeleteButtonForHost = (host) => {
      // Wir suchen in Host + bis zu 4 Eltern-Containern nach "Löschen/Entfernen"
      const delRe = /\b(löschen|entfernen|delete|remove|trash)\b/i;

      const candidatesIn = (root) => {
        const btnSel = 'button, [role="button"], [data-testid], .MuiButton-root, [class*="button"], [class*="IconButton"]';
        return deepQSA(btnSel, root).filter(isVisible);
      };

      const scoreBtn = (btn) => {
        const txt = (btn.innerText ?? btn.textContent ?? '').trim();
        const aria = (btn.getAttribute?.('aria-label') ?? btn.getAttribute?.('title') ?? '').trim();
        const tid = (btn.getAttribute?.('data-testid') ?? '').trim();
        const all = `${txt} ${aria} ${tid}`.toLowerCase();

        let s = 0;
        if (delRe.test(all)) s += 50;
        if (/delete|remove|trash|löschen|entfernen/i.test(tid)) s += 25;
        // Icon-only Buttons: oft aria-label enthält delete/remove
        if (!txt && aria) s += 5;
        return s;
      };

      let node = host;
      for (let i = 0; i < 5 && node; i++) {
        const btns = candidatesIn(node);
        let best = null, bestScore = 0;
        for (const b of btns) {
          const sc = scoreBtn(b);
          if (sc > bestScore) { bestScore = sc; best = b; }
        }
        if (best && bestScore >= 35) return best;
        node = node.parentElement;
      }
      return null;
    };

    const tryConfirmDeleteModal = async () => {
      // Manche UIs fragen nach Bestätigung ("Löschen" / "Delete")
      const dialog =
        deepQS('[role="dialog"]') ||
        deepQS('.MuiDialog-root, .MuiModal-root, [class*="Dialog"], [class*="Modal"]');
      if (!dialog || !isVisible(dialog)) return false;

      const btns = deepQSA('button, [role="button"], .MuiButton-root', dialog).filter(isVisible);
      const okRe = /\b(löschen|delete|entfernen|remove|ok|bestätigen|confirm)\b/i;
      const cancelRe = /\b(abbrechen|cancel|zurück|nein)\b/i;

      let best = null;
      for (const b of btns) {
        const t = ((b.innerText ?? b.textContent ?? '') + ' ' +
                   (b.getAttribute?.('aria-label') ?? '') + ' ' +
                   (b.getAttribute?.('title') ?? '')).trim();
        if (!t) continue;
        if (cancelRe.test(t)) continue;
        if (okRe.test(t)) { best = b; break; }
      }
      if (best) {
        best.click();
        await sleep(120);
        return true;
      }
      return false;
    };

    // 1) Hosts holen – wenn keine: ggf. Add klicken (falls vorhanden)
    let hosts = getHosts();
    if (!hosts.length) {
      try {
        const addBtn = (typeof CUE === 'object' && CUE?._tabs?.cueFindAddParagraphButton)
          ? CUE._tabs.cueFindAddParagraphButton(scope)
          : null;
        if (addBtn) {
          addBtn.click();
          await sleep(120);
          // auf neuen Editor warten
          if (typeof CUE === 'object' && CUE?._tabs?.cueWaitForEditableInside) {
            await CUE._tabs.cueWaitForEditableInside(bodyIds, { timeout: 2500, scope });
          } else {
            await sleep(500);
          }
          hosts = getHosts();
        }
      } catch {}
    }

    if (!hosts.length) {
      if (doToast) smxToast('CUE Absatz-Cleaner: Keine Body-Absätze gefunden.', false);
      return { ok: false, removed: 0, remaining: 0, cleared: 0 };
    }

    // 2) Alle Editoren leeren (auch die, die gleich gelöscht werden)
    for (const h of hosts) {
      const ed = pickEditor(h);
      if (clearEditor(ed)) cleared++;
    }

    // 3) Überschüssige Paragraph-Story-Elemente löschen, bis nur "keep" übrig sind
    let safety = 0;
    while (hosts.length > keep && safety < maxRemove) {
      safety++;

      // Wir lassen den ersten Host stehen, löschen ab Index 1 rückwärts (stabiler)
      const toDelete = hosts.slice(keep).reverse();
      let didDeleteAny = false;

      for (const h of toDelete) {
        // delete Button finden
        const delBtn = findDeleteButtonForHost(h);
        if (!delBtn) {
          // kein Delete-Button → wenigstens leer lassen
          continue;
        }

        // Klick + ggf. Modal bestätigen
        delBtn.click();
        await sleep(120);
        await tryConfirmDeleteModal();

        // warten, dass Host aus reflektiertem DOM verschwindet
        await waitFor(() => !document.contains(h), { timeout: 2500, poll: 80, root: document.body });

        removed++;
        didDeleteAny = true;
      }

      // neu evaluieren
      hosts = getHosts();

      // Wenn nichts gelöscht wurde, brechen wir ab (sonst Endlosschleife)
      if (!didDeleteAny) break;
    }

    // 4) Sicherstellen: mindestens 1 Host existiert
    hosts = getHosts();
    if (!hosts.length) {
      try {
        if (typeof CUE === 'object' && CUE?._tabs?.cueEnsureBodyParagraphElements) {
          await CUE._tabs.cueEnsureBodyParagraphElements(1, scope);
        } else {
          const addBtn = (typeof CUE === 'object' && CUE?._tabs?.cueFindAddParagraphButton)
            ? CUE._tabs.cueFindAddParagraphButton(scope)
            : null;
          if (addBtn) addBtn.click();
        }
        await sleep(150);
      } catch {}
      hosts = getHosts();
    }

    // 5) Final: den verbleibenden ersten Editor garantiert leer machen
    const first = hosts[0];
    const firstEd = first ? pickEditor(first) : null;
    if (clearEditor(firstEd)) cleared++;


    // Wenn CUE am Ende alle Absätze entfernt hat -> einen neuen erzeugen
    hosts = getHosts();
    if (hosts.length < keep) {
      const added = await cueClickAddParagraph(scope);
      if (added) {
        // warten, bis mindestens 1 Body-Host wieder da ist
        await waitFor(() => getHosts().length >= 1, { timeout: 3000, poll: 80, root: document.body });
        hosts = getHosts();

        // den neu erzeugten Absatz sicher leer lassen
        const ed = hosts[0] ? pickEditor(hosts[0]) : null;
        if (clearEditor(ed)) cleared++;
      }
    }

    if (doToast) smxToast(`CUE Absatz-Cleaner: ${removed} gelöscht, ${hosts.length} übrig.`);
    return { ok: true, removed, remaining: hosts.length, cleared };
  } catch (e) {
    try { console.warn('[SMX][CUE][Absatz-Cleaner] Fehler:', e); } catch {}
    if (doToast) smxToast('CUE Absatz-Cleaner: Fehler (Konsole prüfen).', false);
    return { ok: false, removed, remaining: 0, cleared };
  } finally {
    cueCleanBodyToSingleParagraph.__lock = false;
  }
}

//// KAPITEL 2.4 // Hilfsfunktionen ////////////////////////////////////////////////////////////////
function normalizeSpace(s){ return String(s ?? '').replace(/\s+/g,' ').trim(); }
function normalizePreserveNewlines(s){ return String(s ?? '').replace(/[ \t]+\n/g, '\n').replace(/\n{3,}/g, '\n\n').trim(); }
function deepQS(sel, root=document){ try{ return root.querySelector(sel); }catch{ return null; } }
function deepQSA(sel, root=document){ try{ return Array.from(root.querySelectorAll(sel)); }catch{ return []; } }
function isVisible(el){ try{ const r=el.getBoundingClientRect(); return !!(r.width||r.height) && getComputedStyle(el).visibility!=='hidden'; }catch{ return !!el; } }
function sleep(ms){ return new Promise(r=>setTimeout(r, ms)); }
// Clipboard: zuverlässig leeren (Tampermonkey/GM bevorzugt)
async function smxClipboardClear() {
  // 1) Tampermonkey / Greasemonkey API (am zuverlässigsten, kein Permission-Drama)
  try {
    if (typeof GM_setClipboard === 'function') {
      GM_setClipboard('', { type: 'text', mimetype: 'text/plain' });
      return true;
    }
  } catch {}

  // 2) Standard Clipboard API (kann Permission/User-Gesture brauchen)
  try {
    if (navigator?.clipboard?.writeText) {
      await navigator.clipboard.writeText('');
      return true;
    }
  } catch {}

  // 3) Legacy-Fallback (selten nötig; kann in modernen Browsern eingeschränkt sein)
  try {
    const ta = document.createElement('textarea');
    ta.value = '';
    ta.setAttribute('readonly', '');
    ta.style.cssText = 'position:fixed;left:-9999px;top:-9999px;opacity:0;';
    document.body.appendChild(ta);
    ta.select();
    document.execCommand('copy');
    ta.remove();
    return true;
  } catch {}

  return false;
}
async function waitFor(fn, {timeout=2000, poll=60, root=document.body}={}){ const t0=Date.now(); return new Promise(res=>{ const tick=()=>{ try{ if(fn()) return res(true); }catch{} if(Date.now()-t0>=timeout) return res(false); setTimeout(tick, poll); }; tick(); }); }
function readGeneric(el){ try{ if(!el) return ''; const t=el.value ?? el.innerText ?? el.textContent ?? ''; return String(t); }catch{ return ''; } }
function writeGeneric(el, value){ try{ const str=String(value ?? ''); if(!el) return false; if('value' in el){ el.value=str; el.dispatchEvent?.(new InputEvent('input',{bubbles:true})); el.dispatchEvent?.(new Event('change',{bubbles:true})); return true; } el.textContent=str; el.dispatchEvent?.(new InputEvent('input',{bubbles:true})); el.dispatchEvent?.(new Event('change',{bubbles:true})); return true; }catch{ return false; } }
function highlight(el,color='#1b8d3d'){ if(!el) return; const prev=el.style.outline; el.style.outline=`2px solid ${color}`; el.scrollIntoView?.({block:'center',behavior:'smooth'}); setTimeout(()=>{ el.style.outline=prev; },1200); }

//// KAPITEL 2.5 // Shared Site Helpers ////////////////////////////////////////////////////////////
//// Canonicals & Mapping für Ausgabe-Kürzel (aus CFG.SUPERRED.editionMap) /////////////////////////
function smxCanonLoc(s){
  try{
    return String(s??'')
      .normalize('NFD').replace(/[\u0300-\u036f]/g,'')         // Diakritika entfernen
      .replace(/[–—\-]/g,'-').replace(/[.,:;!?()\[\]]+/g,'')   // Satzzeichen glätten
      .replace(/\s+/g,' ').trim().toLowerCase();
  }catch{ return String(s??'').trim().toLowerCase(); }
}

const SMX_LOCALITY_TO_CODES = (function buildLocalityIndex(){
  const map = new Map();
  try{
    const edMap = CFG?.SUPERRED?.editionMap ?? {};
    for(const [code, list] of Object.entries(edMap)){
      for(const raw of (list ?? [])){
        const key = smxCanonLoc(raw);
        if(!map.has(key)) map.set(key, new Set());
        map.get(key).add(code);
      }
    }
  }catch{}
  return map;
})();

function smxCodesForLocalityName(name){
  const key = smxCanonLoc(name);
  return new Set(SMX_LOCALITY_TO_CODES.get(key) ?? []);
}

// SuperRED: Locality-Workflow nach editionMap (gültig/ungültig + Feldreihenfolge)
function smxBuildValidLocalityIndex() {
  const map = new Map(); // canon -> prettyName (erste Schreibweise)
  try {
    const edMap = CFG?.SUPERRED?.editionMap ?? {};
    for (const list of Object.values(edMap)) {
      for (const raw of (list ?? [])) {
        const pretty = String(raw ?? '').trim();
        if (!pretty) continue;
        const canon = smxCanonLoc(pretty);
        if (!canon) continue;
        if (!map.has(canon)) map.set(canon, pretty);
      }
    }
  } catch {}
  return map;
}

const SMX_VALID_LOCALITY = smxBuildValidLocalityIndex();

function smxIsValidLocalityName(name) {
  const canon = smxCanonLoc(name);
  return !!canon && SMX_VALID_LOCALITY.has(canon);
}

// Boundary-Check in canonical text: Treffer darf nicht mitten im Wort liegen
function smxIsWordBoundaryAt(canonText, start, len) {
  const isWordChar = (ch) => /[a-z0-9äöüß]/i.test(ch);
  const before = start > 0 ? canonText[start - 1] : ' ';
  const after = (start + len) < canonText.length ? canonText[start + len] : ' ';
  return !isWordChar(before) && !isWordChar(after);
}

// Findet "erste Ortsmarke" im Text; Berlin kann ausgeschlossen werden
function smxFindFirstLocalityInText(text, { excludeBerlin = true } = {}) {
  const canonText = smxCanonLoc(text);
  if (!canonText) return '';

  let best = { pos: Infinity, name: '' };

  for (const [canonName, pretty] of SMX_VALID_LOCALITY.entries()) {
    if (!canonName) continue;
    if (excludeBerlin && canonName === 'berlin') continue;

    const pos = canonText.indexOf(canonName);
    if (pos < 0) continue;
    if (!smxIsWordBoundaryAt(canonText, pos, canonName.length)) continue;

    if (pos < best.pos) best = { pos, name: pretty };
  }

  return best.name || '';
}

function smxFindLocalityViaAliases(text) {
  const list = CFG?.SUPERRED?.localityAliases ?? [];
  if (!list.length) return '';

  const canonText = smxCanonLoc(text);
  if (!canonText) return '';

  let best = { pos: Infinity, locality: '' };

  for (const entry of list) {
    const needleRaw = Array.isArray(entry) ? entry[0] : entry?.match;
    const locRaw = Array.isArray(entry) ? entry[1] : entry?.locality;

    if (!needleRaw || !locRaw) continue;
    if (!smxIsValidLocalityName(locRaw)) continue;

    const canonNeedle = smxCanonLoc(needleRaw);
    if (!canonNeedle) continue;

    // robust: Wortgrenzen statt indexOf
    const re = new RegExp(`\\b${smxEscapeRegex(canonNeedle)}\\b`, 'i');
    const m = canonText.match(re);
    if (!m) continue;

    const pos = m.index ?? 0;

    if (pos < best.pos) {
      best = { pos, locality: String(locRaw).trim() };
    }
  }

  return best.locality || '';
}
function smxEscapeRegex(s){
  return String(s ?? '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function smxBuildStreetIndex() {
  const raw = CFG?.SUPERRED?.streetDirectory ?? {};
  const rows = [];

  for (const [street, entry] of Object.entries(raw)) {
    const prettyStreet = String(street ?? '').trim();
    if (!prettyStreet) continue;

    const canonStreet = smxCanonLoc(prettyStreet);
    if (!canonStreet) continue;

    rows.push({
      street: prettyStreet,
      canonStreet,
      entry: entry ?? {}
    });
  }

  // längere Straßennamen zuerst, damit z. B. "Afrikanische Straße"
  // nicht von einem kürzeren Teilstring gestört wird
  rows.sort((a, b) => b.canonStreet.length - a.canonStreet.length);
  return rows;
}

const SMX_STREET_INDEX = smxBuildStreetIndex();

function smxResolveStreetSegmentLocality(entry, houseNumber) {
  const num = Number(houseNumber);
  if (!Number.isFinite(num)) return '';

  const segments = Array.isArray(entry?.segments) ? entry.segments : [];
  if (!segments.length) return '';

  const isEven = (num % 2) === 0;

  for (const seg of segments) {
    const from = Number(seg?.from);
    const to = Number(seg?.to);
    const parity = String(seg?.parity ?? 'both').toLowerCase();
    const locality = String(seg?.locality ?? '').trim();

    if (!locality || !Number.isFinite(from) || !Number.isFinite(to)) continue;
    if (num < from || num > to) continue;

    if (
      parity === 'both' ||
      (parity === 'even' && isEven) ||
      (parity === 'odd'  && !isEven)
    ) {
      return locality;
    }
  }

  return '';
}

/**
 * Sucht Straßentreffer im Text und leitet - wenn möglich - einen Ortsteil ab.
 *
 * Regeln:
 * - Straße mit genau 1 locality => eindeutiger Treffer ("single")
 * - Straße mit segments + Hausnummer => segmentierter Treffer ("segment")
 * - mehrdeutige Straße ohne Segmenttreffer => kein Treffer
 */
function smxPassesContextFilter(variant, fullText) {
  const white = variant.white ?? [];
  const black = variant.black ?? [];

  const textCanon = smxCanonLoc(fullText);

  // Blacklist blockiert sofort
  for (const b of black) {
    const bc = smxCanonLoc(b);
    if (textCanon.includes(bc)) {
      return false;
    }
  }

  // Whitelist: muss matchen, wenn vorhanden
  if (white.length) {
    return white.some(w => {
      const wc = smxCanonLoc(w);
      return textCanon.includes(wc);
    });
  }
  return true; // Standard: erlaubt
}
function smxExtractStreetLocalityHits(text) {
  const canonText = smxCanonLoc(text);
  if (!canonText) return [];

  const hits = [];

  for (const item of SMX_STREET_INDEX) {
    let start = 0;

    while (start < canonText.length) {
      const pos = canonText.indexOf(item.canonStreet, start);
      if (pos < 0) break;

      // Wortgrenze absichern
      if (!smxIsWordBoundaryAt(canonText, pos, item.canonStreet.length)) {
        start = pos + item.canonStreet.length;
        continue;
      }

      const after = canonText.slice(pos + item.canonStreet.length, pos + item.canonStreet.length + 24);
      const before = canonText.slice(Math.max(0, pos - 24), pos);
      const context = (before + ' ' + after).toLowerCase();

      let houseNumber = null;

      let m = after.match(/^\s{0,4}(?:nr\.?\s*)?(\d{1,4})\b/i);
      if (m) {
        houseNumber = parseInt(m[1], 10);
      } else {
        m = before.match(/(\d{1,4})\s*$/i);
        if (m) houseNumber = parseInt(m[1], 10);
      }

      const rawEntry = item.entry ?? {};
      const variants = Array.isArray(rawEntry.variants)
        ? rawEntry.variants
        : [rawEntry];

      for (const variant of variants) {

        // optional: Kontextfilter (Whitelist / Blacklist)
        if (typeof smxPassesContextFilter === 'function') {
          if (!smxPassesContextFilter(variant, canonText)) {
            continue;
          }
        }

        const entryLocalities = Array.isArray(variant.localities)
          ? variant.localities
          : [];

        let locality = '';
        let mode = '';

        // 1) segmentiert
        if (houseNumber != null) {
          const segLoc = smxResolveStreetSegmentLocality(variant, houseNumber);
          if (segLoc && smxIsValidLocalityName(segLoc)) {
            locality = segLoc;
            mode = 'segment';
          }
        }

        // 2) eindeutig
        if (!locality && entryLocalities.length === 1) {
          const singleLoc = entryLocalities[0];
          if (singleLoc && smxIsValidLocalityName(singleLoc)) {
            locality = singleLoc;
            mode = 'single';
          }
        }

        // 3) Treffer
        if (locality) {
          hits.push({
            street: item.street,
            locality,
            houseNumber,
            mode,
            pos
          });
          continue;
        }

        // 4) Soft-Hits
        if (houseNumber == null && entryLocalities.length > 1) {
          for (const loc of entryLocalities) {
            if (smxIsValidLocalityName(loc)) {
              hits.push({
                street: item.street,
                locality: loc,
                houseNumber: null,
                mode: 'ambiguous',
                pos
              });
            }
          }
        }
      }

      start = pos + item.canonStreet.length;
    }
  }

  return hits;
}
/**
 * Gewichtete Ortsmarkenanalyse
 * Regeln:
 * 1) localityAliases schlagen alles (harte Dominanz)
 * 2) ansonsten Punktesystem über Titel, Subline, Body
 * 3) editionMap nur zur Validierung
 * 4) Fallback: Berlin
 */
function smxDeriveWeightedLocality({
  headline = '',
  subline = '',
  body = '',
  debug = false
} = {}) {
  const score = Object.create(null);

  // --- Helper ------------------------------------------------------------------------------------
  const addScore = (name, points, reason) => {
    if (!name) return;
    const canon = smxCanonLoc(name);
    if (!smxIsValidLocalityName(name)) return;

    score[canon] ??= { name, points: 0, reasons: [] };
    score[canon].points += points;
    score[canon].reasons.push(`${points > 0 ? '+' : ''}${points}: ${reason}`);
  };

  const scanText = (text, points, reason) => {
    if (!text) return;
    const found = smxFindFirstLocalityInText(text, { excludeBerlin: true });
    if (found) addScore(found, points, reason);
  };

const scanStreetText = (text, singlePoints, segmentPoints, reason) => {
    if (!text) return;

    const hits = smxExtractStreetLocalityHits(text);
    if (!hits.length) return;

    const seen = new Set();

    for (const hit of hits) {
      const key = `${hit.street}|${hit.locality}|${hit.houseNumber ?? ''}|${hit.mode}`;
      if (seen.has(key)) continue;
      seen.add(key);

// NEU >
let pts = 1; // ← WICHTIG: Default setzen

if (hit.mode === 'segment') {
  pts = segmentPoints;
} else if (hit.mode === 'single') {
  pts = singlePoints;
} else if (hit.mode === 'ambiguous') {
  pts = 1; // explizit, aber redundant
}
// < NEU
      const detail = hit.houseNumber != null
        ? `${hit.street} ${hit.houseNumber}`
        : hit.street;

      addScore(
        hit.locality,
        pts,
        `Straße (${detail}, ${reason}, ${hit.mode})`
      );
    }
  };

  // 1) HARTE REGEL: Aliases zuerst (gewinnen sofort)
  for (const txt of [body, subline, headline]) {
    const viaAlias = smxFindLocalityViaAliases(txt);
    if (viaAlias && smxIsValidLocalityName(viaAlias)) {
      if (debug) console.info('[SMX][locality] Alias-Treffer:', viaAlias);
      // return viaAlias;
      addScore(viaAlias, 5, 'Alias'); // Bugfix
    }
  }

  // 2) Gewichtete Auswertung

  // Headline
  scanText(headline, 4, 'Überschrift');

  // Unterzeile
  scanText(subline, 3, 'Unterzeile');

  // Straßennamen
  const sw = CFG?.SUPERRED?.streetWeights ?? {};
  const wSingle  = sw.single  ?? { headline: 2, subline: 2, first: 2, other: 1 };
  const wSegment = sw.segment ?? { headline: 3, subline: 3, first: 3, other: 2 };

  scanStreetText(headline, wSingle.headline, wSegment.headline, 'Überschrift');
  scanStreetText(subline,  wSingle.subline,  wSegment.subline,  'Unterzeile');

  // Body nach Absätzen
  const paragraphs = String(body)
    .split(/\n{2,}/)
    .map(p => p.trim())
    .filter(Boolean);

  paragraphs.forEach((p, idx) => {
    const isFirst = idx === 0;
    const reason = isFirst ? 'erster Absatz' : 'weiterer Absatz';

    scanText(
      p,
      isFirst ? 3 : 1,
      reason
    );

    scanStreetText(
      p,
      isFirst ? wSingle.first : wSingle.other,
      isFirst ? wSegment.first : wSegment.other,
      reason
    );
  });

  // Bonus: Ortsadjektiv / Projektname (z. B. "Marzahner Knoten")
  const projectBonusRegex = /\b([A-ZÄÖÜ][a-zäöüß]+?)er\s+(Brücke|Tunnel|Knoten|Projekt|Bau)\b/g;
  let m;
  while ((m = projectBonusRegex.exec(`${headline} ${subline}`))) {
    const maybeOrt = m[1];
    if (smxIsValidLocalityName(maybeOrt)) {
      addScore(maybeOrt, 2, 'Projektname');
    }
  }

  // 3) Sieger bestimmen
  const entries = Object.values(score).sort((a, b) => b.points - a.points);

  if (entries.length && entries[0].points > 0) {
    if (debug) {
      console.group('[SMX][locality] Gewichtung');
      entries.forEach(e =>
        console.log(
          e.name,
          e.points,
          e.reasons.join(' | ')
        )
      );
      console.groupEnd();
    }
    return entries[0].name;
  }

  // 4) Fallback
  return 'Berlin';
}

// CUE-Workflow für 'locality': Behalte vorhandene gültige Ortsmarke (≠ Berlin) → dann Aliases (bevorzugt) → dann editionMap → Fallback Berlin
function smxDeriveLocalityForSuperRED_CUE({ existing, body, subline, headline, headline_pro }) {

  // vorhandene gültige Ortsmarke behalten (≠ Berlin)
  if (existing && smxIsValidLocalityName(existing) && smxCanonLoc(existing) !== 'berlin') {
    return existing;
  }

  return smxDeriveWeightedLocality({
    headline,
    subline,
    body,
    debug: false // bei Bedarf true setzen
  });
}

// CUE: Body kann aus mehreren Paragraph-Story-Elementen bestehen (Diese Funktion sammelt alle passenden Editoren und fügt den Text zusammen.)
function cueReadAllBodyParagraphsText(scope = document) {
  try {
    const bodyIds = (CUE?._tabs?.TESTIDS?.body ?? []);
    if (!bodyIds.length) return '';

    const texts = [];

    const pickEditor = (host) =>
      deepQS('.ql-editor[contenteditable="true"]', host) ||
      deepQS('[contenteditable="true"]', host) ||
      deepQS('textarea, input[type="text"], input[type="search"], [role="textbox"]', host);

    for (const tid of bodyIds) {
      const hosts = deepQSA(`[data-testid="${tid}"]`, scope);
      for (const host of hosts) {
        const ed = pickEditor(host);
        if (!ed) continue;
        const t = normalizePreserveNewlines(readGeneric(ed));
        if (t) texts.push(t);
      }
    }

    // Dedupe (falls CUE dieselben Blöcke mehrfach rendert)
    const uniq = Array.from(new Set(texts));
    return normalizePreserveNewlines(uniq.join('\n\n'));
  } catch {
    return '';
  }
  }

function smxComputeEditionCodes(values){ // values: { locality?, subline, body }
  const cfg = CFG?.SUPERRED ?? {};
  const maxCodes = Math.max(1, Number(cfg.maxEditionCodes ?? 3));
  const blacklist = new Set((cfg.localityBlacklist ?? []).map(smxCanonLoc));
  const FALLBACK = 'DL';
  const codesOrdered = [];

  const pushCodes = (codes) => {
    for (const c of codes) {
      if (!codesOrdered.includes(c)) codesOrdered.push(c);
      if (codesOrdered.length >= maxCodes) return;
    }
  };

  // CUE-Auto-Lift: Falls locality nicht übergeben wurde, direkt aus CUE-Feld holen
  try {
    const isCUE = typeof CUE === 'object' && CUE?.detect?.();
    if (isCUE && (!values || !values.locality)) {
      // 1) Rohwert aus dem CUE-Feld 'locality' lesen (falls vorhanden)
      const f = CUE.getFields?.() ?? {};
      const rawLoc = (f.locality ? CUE.read?.(f.locality) ?? readGeneric(f.locality) : '').trim();

      // 2) Wenn leer, aus Inhalten ableiten (CUE-Workflow: Alias first, dann editionMap)
      const derivedLoc = rawLoc || smxDeriveLocalityForSuperRED_CUE({
        existing: rawLoc,
        body: cueReadAllBodyParagraphsText(),
        subline: f.subline ? CUE.read?.(f.subline) ?? readGeneric(f.subline) : '',
        headline: f.headline ? CUE.read?.(f.headline) ?? readGeneric(f.headline) : '',
        headline_pro: f.headline_pro ? CUE.read?.(f.headline_pro) ?? readGeneric(f.headline_pro) : ''
      });

      if (derivedLoc) {
        values = { ...(values ?? {}), locality: derivedLoc.trim() };
      }
    }
  } catch { /* silent */ }

  // 1) PRIMÄR: Feld 'locality' bevorzugen, falls vorhanden ->  wenn gültiger Ortsname: direkt mappen -> sonst: Alias-Mapping für locality-String versuchen (z.B. "Südkreuz" -> "Schöneberg")
  (function preferLocalityFieldFirst() {
    const raw = String(values?.locality ?? '').trim();
    if (!raw) return;

    let chosen = '';
    if (smxIsValidLocalityName(raw)) {
      chosen = raw;
    } else {
      // locality-String könnte selbst ein Alias enthalten
      const viaAlias = smxFindLocalityViaAliases(raw);
      if (viaAlias && smxIsValidLocalityName(viaAlias)) {
        chosen = viaAlias;
      }
    }
    if (chosen) {
      const setCodes = smxCodesForLocalityName(chosen);
      const filtered = [...setCodes].filter(c => c !== 'DL' || codesOrdered.length === 0);
      pushCodes(filtered);
    }
  })();

  // 2) SEKUNDÄR: Alias- & editionMap-Detektion im Text (wie bisher)
  const b = String(values?.body ?? '');
  const s = String(values?.subline ?? '');

  // 2a) Aliase im gesamten Text (body -> subline)
  const aliasPrimary =
    smxFindLocalityViaAliases(b) ||
    smxFindLocalityViaAliases(s);

  // 2b) editionMap (erste gültige Ortsmarke, Berlin ausgeschlossen)
  const mapPrimary =
    aliasPrimary ||
    smxFindFirstLocalityInText(b, { excludeBerlin: true }) ||
    smxFindFirstLocalityInText(s, { excludeBerlin: true }) ||
    '';

  const localityPrimary = mapPrimary || 'Berlin';
  const primaryCodes = smxCodesForLocalityName(localityPrimary);
  const filteredPrimary = [...primaryCodes].filter(c => c !== 'DL' || codesOrdered.length === 0);
  pushCodes(filteredPrimary);

  // 2c) Weitere Ortsnennungen im Body (Token-Scan), inkl. Alias-Prüfung pro Token
  const tokens = b.split(/[\s\n\r\t,.;:\(\)–—\-]+/);
  for (const w of tokens) {
    const name = w.trim();
    if (!name) continue;
    const canon = smxCanonLoc(name);
    if (blacklist.has(canon)) continue;

    // Alias -> Codes
    const viaAlias = smxFindLocalityViaAliases(name);
    if (viaAlias) {
      const aliasCodes = smxCodesForLocalityName(viaAlias);
      const filtered = [...aliasCodes].filter(c => c !== 'DL' || codesOrdered.length === 0);
      pushCodes(filtered);
      if (codesOrdered.length >= maxCodes) break;
      continue;
    }

    // editionMap exakte Namen -> Codes
    const codes = smxCodesForLocalityName(name);
    if (codes.size) {
      const filtered = [...codes].filter(c => c !== 'DL' || codesOrdered.length === 0);
      pushCodes(filtered);
      if (codesOrdered.length >= maxCodes) break;
    }
  }

  // 3) DL-Fallback-Logik: nur wenn KEIN anderer Code existiert
  const hasNonDL = codesOrdered.some(c => c !== 'DL');
  if (hasNonDL) {
    for (let i = codesOrdered.length - 1; i >= 0; i--) {
      if (codesOrdered[i] === 'DL') codesOrdered.splice(i, 1);
    }
  } else if (codesOrdered.length === 0) {
    codesOrdered.push(FALLBACK);
  }

  // Für das Dateinamen-Präfix werden Codes mit ' II ' verkettet
  return codesOrdered.join(' II ');
}

// KW/Datumshilfen (für SuperRED & SuperNOTES)
function isoWeekString(d){
  const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  const dow = date.getUTCDay();
  const dayNum = (dow===0?7:dow);
  date.setUTCDate(date.getUTCDate()+4-dayNum);
  const yearStart = new Date(Date.UTC(date.getUTCFullYear(),0,1));
  const weekNo = Math.ceil((((date - yearStart)/86400000)+1)/7);
  return String(weekNo).padStart(2,'0');
}
function nextWeekday(date, weekday){ // Mo=1 ... So=7
  const dd = new Date(date); const day = dd.getDay();
  const w = (typeof weekday==='number'?weekday:1);
  let delta = (w - day + 7) % 7; if(delta===0) delta=7;
  dd.setDate(dd.getDate()+delta); return dd;
}
function redaktionsKWString(now, weekday){ // „redaktionsschluss“ Modus
  const d = new Date(now); const day = d.getDay();
  const rsDay = (typeof weekday==='number')?weekday:1;
  if(day===rsDay) return isoWeekString(d);
  const nm = nextWeekday(d, rsDay); return isoWeekString(nm);
}
function isoWeekToDate(year, week, weekday=(CFG?.SUPERRED?.appearanceWeekday ?? 6)){
  const jan4 = new Date(Date.UTC(year,0,4));
  const jan4Dow = jan4.getUTCDay() || 7;
  const mondayOfW1 = new Date(jan4);
  mondayOfW1.setUTCDate(jan4.getUTCDate() - (jan4Dow - 1));
  const target = new Date(mondayOfW1);
  target.setUTCDate(mondayOfW1.getUTCDate() + ((week-1)*7) + ((weekday-1)));
  return new Date(target.getUTCFullYear(), target.getUTCMonth(), target.getUTCDate());
}
function resolveIssueDateFromKW(kw, weekday=(CFG?.SUPERRED?.appearanceWeekday ?? 6), today=new Date()){
  const y = today.getFullYear();
  const dThis = isoWeekToDate(y, kw, weekday);
  const today0 = new Date(today.getFullYear(), today.getMonth(), today.getDate());
  if(dThis < today0) return isoWeekToDate(y+1, kw, weekday);
  return dThis;
}

// Stichwort-Extraktion (vereinfacht für v6; nutzt CFG.SUPERRED.stichwortMatch)
function smxExtractStichwort(values){
  const cfg = CFG?.SUPERRED ?? {};
  const stems = (cfg.stichwortMatch ?? []).map(s => String(s).toLowerCase());
  const ignoreExact = new Set((cfg.ignoreExact ?? []).map(s => String(s).toLowerCase()));

  function pickFrom(text){
   const raw = String(text ?? '');
   const words = raw.match(/\b[\p{L}\p{M}\-]+\b/gu) ?? [];
   for (const w of words){
     const word = w.trim();
     const low  = word.toLowerCase();
     if(!word || ignoreExact.has(low)) continue;
     if(stems.some(st => low.includes(st))){
       // Originalschreibweise zurückgeben, nur sanft bereinigen
       return word.replace(/[\)\]\].,:;!?]+$/,'').replace(/\s+/g,' ').trim();
     }
   }
   return '';
 }

  // 1) Subline → 2) Body (nur Anfang)
  const try1 = pickFrom(values?.subline ?? '');
  if(try1) return try1;
  const bodyStartRaw = String(values?.body ?? '').slice(0, 280);
  return pickFrom(bodyStartRaw) || '';
}

// Nummern-Erkennung und RED-Dateiname bauen
function guessArticleNumber(list, min = 5, max = 12){
  const re = new RegExp(`\\b(\\d{${min},${max}})\\b`);
  for (const s of list) {
    const m = String(s ?? '').match(re);
    if (m) return m[1];
  }
  return '';
}
function getExistingNumberFromField(inputEl){
  const v = String(inputEl?.value ?? '');
  let m = v.match(/_(\d{5,12})(?:_|$)/u);
  if(m) return m[1];
  m = v.match(/(?:^|\D)(\d{5,12})(?!\d)/u);
  return m ? m[1] : '';
}
function smxSafeHeadline(h){
  return String(h??'').replace(/\s+/g,' ').trim();
}
function smxKw(now=new Date()){
  const cfg = CFG?.SUPERRED ?? {};
  if(!cfg.useKW) return '';
  return (cfg.kwMode === 'redaktionsschluss')
    ? redaktionsKWString(now, cfg.redaktionsschlussWeekday ?? 1)
    : isoWeekString(now);
}

function smxBuildFileName({ kw, kuerzel, nummer, headline, stichwort }){
  const cfg = CFG?.SUPERRED ?? {};
  const delim = String(cfg.filenameDelimiter ?? ' II ');  // überall gleich

  // Segmente
  const segKW      = String(kw ?? '').trim();             // "KW"
  const segAKZ     = String(kuerzel ?? '').trim();        // "AKZ"
  const segArtikel = String(nummer ?? '').trim();         // "Artikel-ID"

  const H = String(headline ?? '').trim();
  const S = String(stichwort ?? '').trim();
  const segTitle = cfg.wrapStichwortInParens && S
    ? `${H || 'ohne Titel'} (${S})`
    : (cfg.headlineFirst ? H : (H ? `${H}${S ? ` (${S})` : ''}` : (S ? `(${S})` : 'ohne Titel')));

  const parts = [];
  if(segKW)      parts.push(segKW);
  if(segAKZ)     parts.push(segAKZ);
  if(segArtikel) parts.push(segArtikel);
  parts.push(segTitle);

  return parts.join(delim); // "KW II AKZ II Artikel-ID II Überschrift (Stichwort)"
}

// Helper: Artikel-ID aus CUE lesen (global verfügbar)
function cueReadArticleIdSafe(){
  try{
    // 1) Primäre Scopes: rechte Metadaten-Spalte / Panels
    const scopes = [
      // Häufige Container im Screenshot:
      '.cue-side-metadata-panel',
      '[class*="metadata-panel"]',
      // Fallbacks: ganze Seite durchsuchen, falls spezifische Container fehlen
      'main', 'body', 'document'
    ];

    // Hilfsfunktion: sichere Normalisierung
    const norm = s => String(s ?? '').toLowerCase().trim();

    // Versuche gezielt: Zeilen mit .row + .left "ID:" + .right selectable
    for (const sel of scopes){
      const root = sel === 'document' ? document : (deepQS(sel) || document);
      if (!root) continue;

      // Kandidaten: DIV.row mit "left"/"right" Spalten
      const rows = deepQSA('.row', root);
      for (const r of rows){
        try{
          const left  = deepQS('.left', r);
          const right = deepQS('.right, .right.selectable', r);
          const isIdLeft = /(^|\b)id(:)?\b/i.test(norm(left?.textContent));
          if (isIdLeft){
            const val = (right?.innerText ?? right?.textContent ?? '').trim();
            const m = val.match(/(\d{5,12})/);
            if (m) return m[1];
          }
          // Fallback: Titelattribut der row
          const title = r.getAttribute?.('title') ?? '';
          const mt = title.match(/\bID:\s*(\d{5,12})\b/i);
          if (mt) return mt[1];
        }catch{}
      }

      // Zweiter Versuch: beliebige Elemente mit sichtbarem "ID:" links und Zahl rechts
      const pairs = deepQSA('[class*="left"], [class*="label"]', root);
      for (const lbl of pairs){
        try{
          if (!/(^|\b)id(:)?\b/i.test(norm(lbl.textContent))) continue;
          const parent = lbl.closest('.row, .property, div') ?? lbl.parentElement;
          const right = parent ? deepQS('.right.selectable, .right, [class*="value"]', parent) : null;
          const val = (right?.innerText ?? right?.textContent ?? '').trim();
          const m = val.match(/(\d{5,12})/);
          if (m) return m[1];
        }catch{}
      }
    }

    // 2) Ultimate fallback: suche nach Textknoten "ID:" irgendwo und nimm die nächste Zahl
    const anyIdText = deepQSA('*').find(el => /\bID:\b/i.test(norm(el.textContent)));
    if (anyIdText){
      const text = anyIdText.textContent ?? '';
      const m = text.match(/\bID:\s*(\d{5,12})\b/i);
      if (m) return m[1];
      // evtl. geschwister "right selectable"
      const sibRight = anyIdText.parentElement ? deepQS('.right.selectable, .right', anyIdText.parentElement) : null;
      const val = (sibRight?.innerText ?? sibRight?.textContent ?? '').trim();
      const mr = val.match(/(\d{5,12})/);
      if (mr) return mr[1];
    }

    // Wenn nichts gefunden:
    return '';
  }catch{
    return '';
  }
}

// Wandelt Plain-Text in <p>...</p>-Absätze um.
// Absatzgrenzen = zwei oder mehr Newlines; einzelne \n werden als <br> behandelt.
function smxPlainTextToHtmlParagraphs(str){
  const esc = (s) => String(s ?? '').replace(/[&<>"']/g, c =>
    ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])
  );
  const normalized = String(str ?? '')
    .replace(/\r\n/g, '\n')
    .replace(/\u00A0/g, ' ');
  const paras = normalized.split(/\n{2,}/);
  return paras.map(p => `<p>${esc(p).replace(/\n/g, '<br>')}</p>`).join('');
}

// — Quill-Writer —
function writeWithQuillAware(el, value, opts = {}) {
  if (typeof SMX_DRY_RUN !== 'undefined' && SMX_DRY_RUN) {
    try { highlight(el, '#ffa726'); } catch {}
    try { console.log('[SMX][Dry-Run] write', { value }); } catch {}
    return true;
  }

const str = String(value ?? '');
  try {
    const container = el.closest?.('.ql-container') ?? el.closest?.('[class*="ql-container"]');
    const quill = container && container.__quill;

    if (quill && typeof quill.getModule === 'function') {
      try { quill.focus?.(); } catch {}
      try { quill.setSelection(0, Math.max(0, (quill.getLength?.() ?? 0))); } catch {}

      try {
        const role = String(opts?.role ?? '').toLowerCase();
        const canPasteHtml = !!(quill.clipboard?.dangerouslyPasteHTML);

        // === CTRL+V-ähnlicher Pfad NUR für CUE-Body ===
        if (role === 'body') {
          // 1) Editor sicher vollständig leeren
          try { quill.deleteText(0, Math.max(0, (quill.getLength?.() ?? 0)), 'user'); } catch {}

          // 2) Möglichst echte "Paste"-Semantik: Plain-Text einfügen -> Quill/CUE erzeugen Absätze aus \n\n wie bei CTRL+V.
          //    Zuerst versuchen wir den Browserpfad:
          let okExec = false;
          try {
            el.focus?.();
            document.execCommand('insertText', false, str); // echte InsertText-Route
            okExec = true;
          } catch { okExec = false; }

          // 3) Fallback: Quill-Clipboard mit HTML-Absätzen
          if (!okExec && canPasteHtml) {
            const html = smxPlainTextToHtmlParagraphs(str);
            quill.clipboard.dangerouslyPasteHTML(0, html, 'user');
          } else if (!okExec && typeof quill.setText === 'function') {
            quill.setText(str, 'user');
          }
        } else {
          // Bisheriges Verhalten für alle anderen Rollen (mit KORREKTEM ESCAPING)
          if (canPasteHtml) {
            try { quill.deleteText(0, Math.max(0, (quill.getLength?.() ?? 0)), 'user'); } catch {}
            const html = String(str)
              .split('\n')
              .map(s => `<p>${s.replace(/[&<>"']/g, c =>
                (c === '<' ? '&lt;' : c === '>' ? '&gt;' :
                 c === '&' ? '&amp;' : c === '"' ? '&quot;' : '&#39;'))}</p>`)
              .join('');
            quill.clipboard.dangerouslyPasteHTML(0, html, 'user');
          } else if (typeof quill.setText === 'function') {
            quill.setText(str, 'user');
          }
        }
      } catch {}

      // Events wie Paste
      const root = quill.root ?? el;
      const fire = (node, ev) => { try { node.dispatchEvent(ev); } catch {} };
      const mkBefore = (type) => new InputEvent('beforeinput', {
        bubbles:true, cancelable:true, inputType: type || 'insertFromPaste', data: str
      });
      fire(root, mkBefore('insertFromPaste'));
      fire(root, new InputEvent('input', { bubbles:true }));
      fire(root, new Event('change', { bubbles:true }));

      try { root.blur?.(); } catch {}
      try { document.body.click?.(); } catch {}
      try { root.dispatchEvent?.(new FocusEvent('focusout', { bubbles:true })); } catch {}

      // Erfolg prüfen (robust, unabhängig von Absatz-/Zeilenformaten)
      const now = readGeneric(root);
      if (normalizeSpace(now) === normalizeSpace(str)) return true;

      try {
        const qtxt = (quill.getText?.() ?? '').replace(/\s+$/,'');
        // Für Body reicht inhaltliches Vorhandensein; für andere Rollen exakter Vergleich
        const role = String(opts?.role ?? '').toLowerCase();
        if (role === 'body' ? (qtxt.length > 0) : (normalizeSpace(qtxt) === normalizeSpace(str))) {
          return true;
        }
      } catch {}
    }
  } catch {}

  // Fallback: generisches Schreiben (nicht-Quill)
  return writeGeneric(el, value);
}

//// KAPITEL 2.6 // DETEKTOR ///////////////////////////////////////////////////////////////////////
function smxAnalyzeLocalityDebug({
  headline = '',
  subline = '',
  body = ''
} = {}) {

  const score = Object.create(null);

  const add = (name, pts, reason) => {
    if (!name || !smxIsValidLocalityName(name)) return;
    const canon = smxCanonLoc(name);

    score[canon] ??= { name, points: 0, reasons: [] };
    score[canon].points += pts;
    score[canon].reasons.push(`${pts >= 0 ? '+' : ''}${pts} ${reason}`);
  };

  // 🔹 Ortsnamen
  const scanText = (text, pts, label) => {
    const found = smxFindFirstLocalityInText(text, { excludeBerlin: true });
    if (found) add(found, pts, `Text (${label})`);
  };

  scanText(headline, 4, 'Überschrift');
  scanText(subline, 3, 'Unterzeile');

  const paragraphs = String(body)
    .split(/\n{2,}/)
    .map(p => p.trim())
    .filter(Boolean);

  paragraphs.forEach((p, i) => {
    scanText(p, i === 0 ? 3 : 1, i === 0 ? 'Lead' : 'Text');
  });

  // 🔹 Straßen
  const scanStreet = (text, label) => {
    const hits = smxExtractStreetLocalityHits(text);

    for (const h of hits) {
      const pts =
        h.mode === 'segment' ? 3 :
        h.mode === 'single'  ? 2 :
        1;

      const detail = h.houseNumber
        ? `${h.street} ${h.houseNumber}`
        : h.street;

      add(h.locality, pts, `Straße (${detail}, ${label}, ${h.mode})`);
    }
  };

  scanStreet(headline, 'Überschrift');
  scanStreet(subline, 'Unterzeile');
  paragraphs.forEach((p, i) =>
    scanStreet(p, i === 0 ? 'Lead' : 'Text')
  );

  // 🔹 Ergebnis sortieren
  return Object.values(score)
    .sort((a, b) => b.points - a.points);
}

// Ausgabe (Overlay optional zuschaltbar)
function smxShowLocalityDebugOverlay(data) {

  const html = `
  <div style="font-weight:700;margin-bottom:8px">
    Ortsanalyse (SuperMAX)
  </div>

  ${data.map(d => `
    <div style="
      margin-top:8px;
      padding:8px;
      border:1px solid #12456a;
      border-radius:6px;
      background:#06263d
    ">
      <div style="font-weight:600">
        ${d.name} — ${d.points} Punkte
      </div>
      <div style="font-size:12px;margin-top:4px">
        ${d.reasons.join('<br>')}
      </div>
    </div>
  `).join('')}

  <div style="margin-top:12px;text-align:right">
    <button id="smx_close_debug"
      style="background:#3a3a3a;color:#fff;border:0;padding:6px 12px;border-radius:6px">
      Schließen
    </button>
  </div>
  `;

  const { wrap, box } = smxCreateOverlayBox(html);

  box.querySelector('#smx_close_debug')
    .addEventListener('click', () => wrap.remove());
}


